// @ts-check

import { AbstractHandler } from './AbstractHandler.js'
import { getRequire } from '../../utils/Runtime.js'

/**
 * @typedef {import('../../utils/Command.js').Command} Command
 */

/** @type {typeof import('fs').existsSync | null} */
let _existsSync = null

/** @type {typeof import('fs').readFileSync | null} */
let _readFileSync = null

/** @type {typeof import('fs').statSync | null} */
let _statSync = null

/** @type {typeof import('path').resolve | null} */
let _resolve = null

/** @type {typeof import('path').join | null} */
let _join = null

/** @type {typeof import('path').dirname | null} */
let _dirname = null

const requireDynamic = getRequire(import.meta.url)

class LoadLibraryHandler extends AbstractHandler {
    requiredParametersCount = 1
    /** @type {string[]} */
    static loadedLibraries = []

    constructor() {
        super()
    }

    /**
     * @param {Command} command
     */
    process(command) {
        this.validate(command, this.requiredParametersCount, this.constructor.name)

        const { payload } = command
        const [lib] = payload

        if (!lib) {
            throw new Error('Cannot load module: Library path is required but was not provided')
        }

        if (!_existsSync) {
            const { existsSync } = requireDynamic('fs')
            _existsSync = existsSync
        }
        if (!_readFileSync || !_statSync) {
            const { readFileSync, statSync } = requireDynamic('fs')
            _readFileSync = readFileSync
            _statSync = statSync
        }
        if (!_resolve) {
            const { resolve } = requireDynamic('path')
            _resolve = resolve
        }
        if (!_join) {
            const { join } = requireDynamic('path')
            _join = join
        }
        if (!_dirname) {
            const { dirname } = requireDynamic('path')
            _dirname = dirname
        }

        // Resolve and pick an existing path (relative or absolute)
        const absolutePath = _resolve ? _resolve(lib) : lib
        const candidatePaths = [lib, absolutePath]
        const existingPath = candidatePaths.find(p => _existsSync && _existsSync(p))

        if (!existingPath) {
            throw new Error(`Cannot load module: Library not found: ${lib}`)
        }

        /**
         * @param {string} packageJsonPath
         * @param {string} packageRootDir
         */
        const resolveModulePathFromPackageJson = (packageJsonPath, packageRootDir) => {
            let packageJson
            try {
                const packageJsonRaw = _readFileSync ? _readFileSync(packageJsonPath, 'utf8') : ''
                packageJson = JSON.parse(packageJsonRaw)
            } catch (error) {
                throw new Error(
                    `Cannot load module: Cannot parse package.json: ${packageJsonPath}\n${error}`
                )
            }

            if (!packageJson.main || typeof packageJson.main !== 'string') {
                throw new Error(
                    `Cannot load module: Missing "main" entry in package.json: ${packageJsonPath}`
                )
            }

            const resolvedModulePath = _join
                ? _join(packageRootDir, packageJson.main)
                : `${packageRootDir}/${packageJson.main}`
            if (!_existsSync || !_existsSync(resolvedModulePath)) {
                throw new Error(`Cannot load module: Entry point not found: ${resolvedModulePath}`)
            }

            return resolvedModulePath
        }

        let modulePath = existingPath
        const isPackageJsonPath = /[\\/]package\.json$/i.test(existingPath)
        if (_statSync && _statSync(existingPath).isDirectory()) {
            const packageJsonPath = _join ? _join(existingPath, 'package.json') : `${existingPath}/package.json`
            if (!_existsSync || !_existsSync(packageJsonPath)) {
                throw new Error(
                    `Cannot load module: package.json not found in directory: ${existingPath}`
                )
            }

            modulePath = resolveModulePathFromPackageJson(packageJsonPath, existingPath)
        } else if (isPackageJsonPath) {
            if (!_dirname) {
                throw new Error('Cannot load module: Unable to resolve package.json directory')
            }
            modulePath = resolveModulePathFromPackageJson(existingPath, _dirname(existingPath))
        }

        // Normalize to absolute path for deduplication
        const normalizedPath = _resolve ? _resolve(modulePath) : modulePath

        // ✅ Load only once per normalized absolute path
        if (LoadLibraryHandler.loadedLibraries.includes(normalizedPath)) {
            return 0
        }

        // Derive global name from file name (using normalized path)
        const pathArray = normalizedPath.split(/[/\\]/)
        let libraryName =
            pathArray.length > 1 ? pathArray[pathArray.length - 1] : pathArray[0]
        libraryName = libraryName.replace(/\.js$/i, '')

        let moduleExports
        try {
            // Use the normalized path when requiring to keep behavior consistent
            moduleExports = requireDynamic(normalizedPath)
            LoadLibraryHandler.loadedLibraries.push(normalizedPath)
        } catch (error) {
            throw new Error('Cannot load module: ' + normalizedPath + '\n' + error)
        }

        // @ts-expect-error
        global[libraryName] = moduleExports

        for (const [key, value] of Object.entries(moduleExports)) {
            // @ts-expect-error
            global[key] = value
        }

        return 0
    }

    getLoadedLibraries() {
        return LoadLibraryHandler.loadedLibraries
    }
}

export { LoadLibraryHandler }
